import{_ as e,o as a,c as r,a2 as o}from"./chunks/framework.c3r8iWL8.js";const p=JSON.parse('{"title":"Guide: CI/CD & Release","description":"Reference template for AI-native enterprise delivery on AWS","frontmatter":{},"headers":[],"relativePath":"guides/ci-cd-release.md","filePath":"guides/ci-cd-release.md","lastUpdated":1782929962000}'),n={name:"guides/ci-cd-release.md"};function d(s,t,i,l,c,h){return a(),r("div",null,[...t[0]||(t[0]=[o('<h1 id="guide-ci-cd-release" tabindex="-1">Guide: CI/CD &amp; Release <a class="header-anchor" href="#guide-ci-cd-release" aria-label="Permalink to &quot;Guide: CI/CD &amp; Release&quot;">​</a></h1><p><strong>Decision:</strong> How changes flow from merge to AWS production safely.</p><p>Related: <a href="./../cicd-observability.html">cicd-observability.md</a> · <a href="./static-analysis-linting.html">static-analysis-linting.md</a> · <a href="./identity-access-secrets.html">identity-access-secrets.md</a> · <a href="./../sops/SOP-006-release-deploy.html">SOP-006</a></p><hr><h2 id="static-analysis-in-the-pipeline" tabindex="-1">Static analysis in the pipeline <a class="header-anchor" href="#static-analysis-in-the-pipeline" aria-label="Permalink to &quot;Static analysis in the pipeline&quot;">​</a></h2><p>Linters, SAST, SCA, and secret scans should run in <strong>CI before</strong> deploy stages. Tool choices and gate thresholds: <a href="./static-analysis-linting.html">Linters &amp; static analysis</a>.</p><hr><h2 id="ci-orchestrator" tabindex="-1">CI orchestrator <a class="header-anchor" href="#ci-orchestrator" aria-label="Permalink to &quot;CI orchestrator&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Option</th><th>Pros</th><th>Cons</th></tr></thead><tbody><tr><td><strong>AWS CodePipeline + CodeBuild</strong></td><td>Native IAM; unified with AWS deploy</td><td>YAML UX; cross-repo patterns harder</td></tr><tr><td><strong>GitHub Actions</strong></td><td>Excellent PR UX; huge action ecosystem</td><td>Hybrid IAM to AWS needs OIDC setup</td></tr><tr><td><strong>GitLab CI</strong></td><td>Single platform if already on GitLab</td><td>Less common in AWS-only shops</td></tr><tr><td><strong>Jenkins</strong></td><td>Flexible</td><td>Operate Jenkins; drift</td></tr></tbody></table><p><strong>Recommended for AWS-primary:</strong> CodePipeline or Actions + OIDC — pick one org standard. IAM and deploy-role design: <a href="./identity-access-secrets.html">Identity, access &amp; secrets</a>.</p><hr><h2 id="deploy-strategies" tabindex="-1">Deploy strategies <a class="header-anchor" href="#deploy-strategies" aria-label="Permalink to &quot;Deploy strategies&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Strategy</th><th>Pros</th><th>Cons</th></tr></thead><tbody><tr><td><strong>Rolling</strong></td><td>Simple</td><td>Slow rollback; blast radius</td></tr><tr><td><strong>Blue/green</strong></td><td>Fast rollback</td><td>Double capacity cost during switch</td></tr><tr><td><strong>Canary (% traffic)</strong></td><td>Early signal</td><td>Requires metric gates + automation</td></tr><tr><td><strong>Feature flags (AppConfig/LaunchDarkly)</strong></td><td>Decouple deploy from release</td><td>Flag debt if not cleaned</td></tr></tbody></table><p><strong>Recommended:</strong> Canary + feature flags for T1; blue/green acceptable; avoid naked rolling for T1.</p><hr><h2 id="ephemeral-pr-environments" tabindex="-1">Ephemeral PR environments <a class="header-anchor" href="#ephemeral-pr-environments" aria-label="Permalink to &quot;Ephemeral PR environments&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Option</th><th>Pros</th><th>Cons</th></tr></thead><tbody><tr><td><strong>Full stack per PR (CDK)</strong></td><td>Realistic E2E</td><td>Cost; slow provisioning</td></tr><tr><td><strong>Shared staging + branch namespace</strong></td><td>Cheaper</td><td>Cross-PR interference</td></tr><tr><td><strong>LocalStack / mocks only</strong></td><td>Fast</td><td>Misses integration gaps</td></tr></tbody></table><p><strong>Pitfall:</strong> Ephemeral envs with prod-like data → compliance violation. Use synthetic fixtures only.</p><hr><h2 id="pitfalls" tabindex="-1">Pitfalls <a class="header-anchor" href="#pitfalls" aria-label="Permalink to &quot;Pitfalls&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Pitfall</th><th>Why it hurts</th><th>Mitigation</th></tr></thead><tbody><tr><td><strong>Deploy without metric gate</strong></td><td>Bad release reaches 100% traffic</td><td>Auto-rollback on error/latency</td></tr><tr><td><strong>Staging ≠ prod parity</strong></td><td>&quot;Worked in staging&quot; incidents</td><td>Same container, scaled-down infra</td></tr><tr><td><strong>Manual prod deploy only</strong></td><td>Human error; slow recovery</td><td>Automate with approval gate for T1</td></tr><tr><td><strong>Skipping container scan</strong></td><td>CVEs in prod</td><td>ECR/Trivy block Critical</td></tr><tr><td><strong>Long-running PR envs</strong></td><td>AWS bill shock</td><td>Auto-destroy on PR close / TTL</td></tr><tr><td><strong>CI and CD in one job</strong></td><td>Can&#39;t retry deploy without retest</td><td>Separate stages with artifacts</td></tr><tr><td><strong>No deploy correlation in metrics</strong></td><td>Can&#39;t blame release</td><td>Tag metrics/traces with version</td></tr><tr><td><strong>Feature flag as permanent if</strong></td><td>Unreachable code paths</td><td>Flag cleanup in Definition of Done</td></tr></tbody></table><hr><h2 id="recommended-starting-point" tabindex="-1">Recommended starting point <a class="header-anchor" href="#recommended-starting-point" aria-label="Permalink to &quot;Recommended starting point&quot;">​</a></h2><p>Actions or CodePipeline → build + test stages → deploy staging → synthetics → canary prod with metric rollback → AppConfig for release toggles.</p><hr><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="./runtime-aws.html">Runtime on AWS</a> · <a href="./automated-testing-qa.html">Automated testing</a> · <a href="./observability-monitoring-qa.html">Observability</a></li></ul>',27)])])}const m=e(n,[["render",d]]);export{p as __pageData,m as default};
